39	export function nextGeneration(cells: Cell[]): Cell[] {
40	  const survivors = cells.filter((cell) => {
41	    const neighborCount = countNeighbors(cell, cells);
42	    return neighborCount === 2 || neighborCount === 3;
43	  });
44	
45	  const births = deadNeighborCandidates(cells).filter(
46	    (candidate) => countNeighbors(candidate, cells) === 3,
47	  );
48	
49	  return [...survivors, ...births];
50	}
